use clap::{Arg, Command};

#[test]
fn test_create_command() {
    let cmd = Command::new("myapp")
        .version("1.0")
        .about("Test app");
    assert_eq!(cmd.get_name(), "myapp");
}

#[test]
fn test_add_argument() {
    let cmd = Command::new("myapp")
        .arg(Arg::new("input").required(true));
    let args: Vec<_> = cmd.get_arguments().collect();
    assert!(args.iter().any(|a| a.get_id() == "input"));
}

#[test]
fn test_parse_args() {
    let cmd = Command::new("myapp")
        .arg(Arg::new("name").short('n').long("name"));
    let matches = cmd.try_get_matches_from(vec!["myapp", "-n", "test"]).unwrap();
    assert_eq!(matches.get_one::<String>("name").unwrap(), "test");
}

/// Set a display name shown in help text instead of the command name.
pub fn display_name(mut self, name: impl Into<String>) -> Self {
    self.display_name = Some(name.into());
    self
}
